const fs = require('fs');
const path = require('path');

const vaultRoot = $env.VAULT_ROOT;
const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const dateStr = yesterday.toISOString().split('T')[0];

const logPath = path.join(vaultRoot, '553 - Trace Chats', `${dateStr}.md`);

if (!fs.existsSync(logPath)) {
  return [{ json: { skip: true, date: dateStr } }];
}

const content = fs.readFileSync(logPath, 'utf8');
return [{ json: { skip: false, date: dateStr, content, logPath } }];

const date = $json.date;
const content = $json.content;

const prompt = `You are summarizing a day of conversations between a user and their AI assistant Trace.

DATE: ${date}

CHAT LOG:
${content}

---

Write a concise summary of this day's conversations. Include:
- Main topics discussed
- Key decisions or actions taken
- Important notes or insights
- Any follow-up items mentioned

Keep it under 400 words. Use plain text, no markdown headers.`;

return [{
  json: {
    date,
    content,
    logPath: $json.logPath,
    body: JSON.stringify({
      model: 'qwen3.5:27b-32k',
      prompt,
      stream: false,
      options: { num_ctx: 8192 },
      think: false
    })
  }
}];

const summary = $json.response || '';
const date = $('Build LLM Body').item.json.date;

if (!summary.trim()) {
  return [{ json: { skip: true } }];
}

return [{
  json: {
    date,
    summary,
    body: JSON.stringify({
      id: date,
      text: summary,
      collection: 'chats',
      metadata: { date, source: '553 - Trace Chats' }
    })
  }
}];
